export type LocalizedString = {
  en: string;
  ar: string;
};

export enum UserRole {
  SEEKER = 'SEEKER',
  OFFICE = 'OFFICE',
  ADMIN = 'ADMIN'
}

export enum ServiceCategory {
  HOME_SERVICE = 'Home Service',
  COOKING = 'Cooking',
  CHILDCARE = 'Childcare',
  DRIVER = 'Driver'
}

export interface Office {
  id: string;
  name: LocalizedString;
  avatar: string;
  coverImage: string;
  bio: LocalizedString;
  location: LocalizedString;
  phone: string;
  rating: number;
  reviewCount: number;
}

export interface Worker {
  id: string;
  officeId: string;
  name: LocalizedString;
  photo: string;
  nationality: LocalizedString;
  gender: 'Female' | 'Male';
  age: number;
  experienceYears: number;
  languages: LocalizedString[];
  category: ServiceCategory;
  availability: 'Available' | 'Reserved' | 'Hired';
  salary: number; // in KWD
  city: LocalizedString;
  createdAt: string; // ISO string for sorting
  lastViewedAt?: string; // ISO string for "Continue from last viewed"
}

export interface Ad {
  id: string;
  officeId: string;
  workerId: string;
  title: LocalizedString;
  description: LocalizedString;
  postedAt: string;
  featured: boolean;
}

export type ViewState = 
  | { type: 'HOME' }
  | { type: 'OFFICE_PROFILE'; officeId: string }
  | { type: 'WORKER_PROFILE'; workerId: string }
  | { type: 'PUBLISH_AD' }
  | { type: 'FAVORITES' }
  | { type: 'OFFICES_LIST' }
  | { type: 'MY_ADS' }
  | { type: 'LEADS' }
  | { type: 'USER_PROFILE' }
  | { type: 'SETTINGS' }
  | { type: 'NOTIFICATIONS' };

import React, { useState, useMemo, useEffect } from 'react';
import { Search, MapPin, ChevronRight, Filter, ChevronLeft, Bell } from 'lucide-react';
import { GlassCard, Badge, Avatar } from '../components/GlassUI';
import { ServiceCategory, Ad, Office, Worker } from '../types';
import { MOCK_ADS, MOCK_OFFICES, MOCK_WORKERS } from '../constants';
import { useLanguage } from '../i18n';

interface HomeProps {
  onSelectWorker: (id: string) => void;
  onSelectOffice: (id: string) => void;
  onNavigateNotifications: () => void;
}

export const Home: React.FC<HomeProps> = ({ onSelectWorker, onSelectOffice, onNavigateNotifications }) => {
  const [activeCategory, setActiveCategory] = useState<ServiceCategory | 'All'>('All');
  const [searchQuery, setSearchQuery] = useState('');
  const { t, dir, language } = useLanguage();

  // Mocking "last viewed" state - normally would be in a store/localStorage
  const [lastViewedIds, setLastViewedIds] = useState<string[]>(() => {
    const saved = localStorage.getItem('last_viewed_workers');
    return saved ? JSON.parse(saved) : ['w1', 'w4']; // Mock defaults
  });

  // Global search & category filter logic
  const baseFilter = (worker: Worker) => {
    const matchesCategory = activeCategory === 'All' || worker.category === activeCategory;
    const searchLower = searchQuery.toLowerCase();
    const matchesSearch = 
      worker.name[language].toLowerCase().includes(searchLower) || 
      worker.nationality[language].toLowerCase().includes(searchLower);
    return matchesCategory && matchesSearch;
  };

  // Section: Continue from last viewed
  const continueViewed = useMemo(() => {
    return MOCK_WORKERS
      .filter(w => lastViewedIds.includes(w.id))
      .sort((a, b) => lastViewedIds.indexOf(a.id) - lastViewedIds.indexOf(b.id))
      .slice(0, 10);
  }, [lastViewedIds]);

  // Section: Available Now
  const availableNow = useMemo(() => {
    return MOCK_WORKERS
      .filter(w => w.availability === 'Available')
      .filter(baseFilter)
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }, [activeCategory, searchQuery, language]);

  // Section: Newest
  const newestListings = useMemo(() => {
    return MOCK_WORKERS
      .filter(baseFilter)
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }, [activeCategory, searchQuery, language]);

  // Section: By Budget
  const budgetListings = useMemo(() => {
    return MOCK_WORKERS
      .filter(baseFilter)
      .sort((a, b) => a.salary - b.salary);
  }, [activeCategory, searchQuery, language]);

  // Section: Highest Experience
  const experiencedListings = useMemo(() => {
    return MOCK_WORKERS
      .filter(baseFilter)
      .sort((a, b) => b.experienceYears - a.experienceYears);
  }, [activeCategory, searchQuery, language]);

  const getTranslatedCategory = (cat: ServiceCategory | 'All') => {
    if (cat === 'All') return t('cat_all');
    if (cat === ServiceCategory.HOME_SERVICE) return t('cat_home_service');
    if (cat === ServiceCategory.COOKING) return t('cat_cooking');
    if (cat === ServiceCategory.CHILDCARE) return t('cat_childcare');
    if (cat === ServiceCategory.DRIVER) return t('cat_driver');
    return cat;
  };

  const handleWorkerClick = (id: string) => {
    // Add to last viewed
    const newHistory = [id, ...lastViewedIds.filter(v => v !== id)].slice(0, 10);
    setLastViewedIds(newHistory);
    localStorage.setItem('last_viewed_workers', JSON.stringify(newHistory));
    onSelectWorker(id);
  };

  return (
    <div className="pb-10">
      {/* Header */}
      <div className="sticky top-0 z-40 bg-background/80 backdrop-blur-xl border-b border-border pb-4 pt-6 px-5 space-y-4 transition-colors">
        <div className="flex items-center justify-between">
          {/* Logo & Name - RTL Right / LTR Left */}
          <div className="flex items-center gap-3">
            <div className="flex-shrink-0">
              <img 
                src="https://raiyansoft.com/wp-content/uploads/2026/02/icon-s-d.png" 
                alt="Logo" 
                className="h-[40px] w-auto max-w-[135px] object-contain"
              />
            </div>
            <div className="hidden min-[360px]:block">
              <h1 className="text-lg font-bold text-primary leading-tight">{t('app_name')}</h1>
              <p className="text-[10px] text-secondary">{t('subtitle')}</p>
            </div>
          </div>

          {/* Notification Bell */}
          <button 
            onClick={onNavigateNotifications}
            className="w-10 h-10 rounded-full bg-glass border border-border flex items-center justify-center text-primary relative hover:bg-glassHigh transition-colors flex-shrink-0"
            aria-label={t('nav_notifications')}
          >
            <Bell size={20} />
            <span className="absolute top-2.5 right-2.5 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-background"></span>
          </button>
        </div>

        {/* Search */}
        <div className="relative group">
          <input 
            type="text" 
            placeholder={t('search_placeholder')}
            className="w-full h-11 bg-glass border border-border rounded-[14px] ps-10 pe-4 text-sm text-primary placeholder-secondary/50 focus:outline-none focus:border-brand-400 focus:bg-glassHigh focus:ring-4 focus:ring-[var(--focus-ring)] transition-all"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <Search className="absolute start-3.5 top-3 text-secondary/70 group-focus-within:text-brand-500 transition-colors" size={18} />
          <button className="absolute end-3 top-2.5 text-accent-text bg-accent-subtle p-1 rounded-md hover:bg-brand-300 transition-colors">
            <Filter size={14} />
          </button>
        </div>

        {/* Categories Strip */}
        <div className="flex gap-2 overflow-x-auto no-scrollbar pt-1">
          <CategoryChip 
            label={getTranslatedCategory('All')} 
            isActive={activeCategory === 'All'} 
            onClick={() => setActiveCategory('All')} 
          />
          {Object.values(ServiceCategory).map(cat => (
            <CategoryChip 
              key={cat} 
              label={getTranslatedCategory(cat)} 
              isActive={activeCategory === cat} 
              onClick={() => setActiveCategory(cat)} 
            />
          ))}
        </div>
      </div>

      <div className="space-y-8 mt-6">
        {/* Section: Continue from last viewed */}
        {continueViewed.length > 0 && (
          <SectionContainer title={t('section_continue')}>
            <div className="flex gap-4 overflow-x-auto no-scrollbar px-5">
              {continueViewed.map(worker => (
                <CompactCard 
                  key={worker.id} 
                  worker={worker} 
                  onClick={() => handleWorkerClick(worker.id)} 
                  language={language}
                />
              ))}
            </div>
          </SectionContainer>
        )}

        {/* Section: Available Now */}
        {availableNow.length > 0 && (
          <SectionContainer title={t('section_available')}>
            <div className="flex gap-4 overflow-x-auto no-scrollbar px-5">
              {availableNow.map(worker => (
                <CompactCard 
                  key={worker.id} 
                  worker={worker} 
                  onClick={() => handleWorkerClick(worker.id)} 
                  language={language}
                  showAvailability
                />
              ))}
            </div>
          </SectionContainer>
        )}

        {/* Section: Newest */}
        <SectionContainer title={t('section_newest')}>
          <div className="px-5 space-y-4">
            {newestListings.slice(0, 3).map(worker => (
              <FullListingCard 
                key={worker.id} 
                worker={worker} 
                onSelect={() => handleWorkerClick(worker.id)}
                onSelectOffice={onSelectOffice}
                language={language}
                t={t}
                dir={dir}
              />
            ))}
          </div>
        </SectionContainer>

        {/* Section: Budget */}
        <SectionContainer title={t('section_budget')}>
          <div className="px-5 space-y-4">
            {budgetListings.slice(0, 3).map(worker => (
              <FullListingCard 
                key={worker.id} 
                worker={worker} 
                onSelect={() => handleWorkerClick(worker.id)}
                onSelectOffice={onSelectOffice}
                language={language}
                t={t}
                dir={dir}
              />
            ))}
          </div>
        </SectionContainer>

        {/* Section: Highest Experience */}
        <SectionContainer title={t('section_experience')}>
          <div className="px-5 space-y-4">
            {experiencedListings.slice(0, 3).map(worker => (
              <FullListingCard 
                key={worker.id} 
                worker={worker} 
                onSelect={() => handleWorkerClick(worker.id)}
                onSelectOffice={onSelectOffice}
                language={language}
                t={t}
                dir={dir}
              />
            ))}
          </div>
        </SectionContainer>
      </div>
    </div>
  );
};

