const CompactCard: React.FC<{ worker: Worker; onClick: () => void; language: string; showAvailability?: boolean }> = ({ worker, onClick, language, showAvailability }) => (
  <div onClick={onClick} className="flex-shrink-0 w-32 cursor-pointer group">
