interface OfficeProfileProps {
  officeId: string;
  onBack: () => void;
  onSelectWorker: (id: string) => void;
}

export const OfficeProfile: React.FC<OfficeProfileProps> = ({ officeId, onBack, onSelectWorker }) => {
