      </div>

      {/* Office Profile Details */}
      <div className="-mt-12 px-5 relative z-10">
        <div className="flex justify-between items-end mb-4">
           <Avatar src={office.avatar} alt={office.name[language]} size="xl" className="border-4 border-background shadow-lg" />
           <div className="flex gap-2 mb-2">
             <Button variant="glass" className="!h-10 !px-3 !rounded-xl hover:text-accent-text transition-all">
