  | { type: 'OFFICE_PROFILE'; officeId: string }
  | { type: 'WORKER_PROFILE'; workerId: string }
  | { type: 'PUBLISH_AD' }
  | { type: 'FAVORITES' }
  | { type: 'OFFICES_LIST' }
  | { type: 'MY_ADS' }
