      .filter(baseFilter)
      .sort((a, b) => lastViewedIds.indexOf(a.id) - lastViewedIds.indexOf(b.id))
      .slice(0, 10);
  }, [lastViewedIds, activeCategory, activeNationality, searchQuery, language]);

  const availableNow = useMemo(() => {
    return MOCK_WORKERS
      .filter(w => w.availability === 'Available')
      .filter(baseFilter)
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }, [activeCategory, activeNationality, searchQuery, language]);

  const newestListings = useMemo(() => {
    return MOCK_WORKERS
      .filter(baseFilter)
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }, [activeCategory, activeNationality, searchQuery, language]);

  const budgetListings = useMemo(() => {
    return MOCK_WORKERS
      .filter(baseFilter)
      .sort((a, b) => a.salary - b.salary);
  }, [activeCategory, activeNationality, searchQuery, language]);

  const experiencedListings = useMemo(() => {
    return MOCK_WORKERS
      .filter(baseFilter)
      .sort((a, b) => b.experienceYears - a.experienceYears);
  }, [activeCategory, activeNationality, searchQuery, language]);

  const getTranslatedCategory = (cat: ServiceCategory | 'All') => {
    if (cat === 'All') return t('cat_all');
    if (cat === ServiceCategory.HOME_SERVICE) return t('cat_home_service');
    if (cat === ServiceCategory.COOKING) return t('cat_cooking');
    if (cat === ServiceCategory.CHILDCARE) return t('cat_childcare');
    if (cat === ServiceCategory.DRIVER) return t('cat_driver');
    return cat;
  };

  const handleWorkerClick = (id: string) => {
    const newHistory = [id, ...lastViewedIds.filter(v => v !== id)].slice(0, 10);
    setLastViewedIds(newHistory);
    localStorage.setItem('last_viewed_workers', JSON.stringify(newHistory));
    onSelectWorker(id);
  };

  return (
    <div className="pb-10">
      <div className="sticky top-0 z-40 bg-background/80 backdrop-blur-xl border-b border-border pb-4 pt-6 px-5 space-y-4 transition-colors">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="flex-shrink-0">
              <img 
                src="https://raiyansoft.com/wp-content/uploads/2026/02/icon-s-d.png" 
                alt="Logo" 
                className="h-[40px] w-auto max-w-[135px] object-contain"
              />
            </div>
            <div className="hidden min-[360px]:block">
              <h1 className="text-lg font-bold text-primary leading-tight">{t('app_name')}</h1>
              <p className="text-[10px] text-secondary">{t('subtitle')}</p>
            </div>
          </div>
          <button 
            onClick={onNavigateNotifications}
            className="w-10 h-10 rounded-full bg-glass border border-border flex items-center justify-center text-primary relative hover:bg-glassHigh transition-colors flex-shrink-0"
            aria-label={t('nav_notifications')}
          >
            <Bell size={20} />
            <span className="absolute top-2.5 right-2.5 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-background"></span>
          </button>
        </div>

        <div className="relative group">
          <input 
            type="text" 
            placeholder={t('search_placeholder')}
            className="w-full h-11 bg-glass border border-border rounded-[14px] ps-10 pe-4 text-sm text-primary placeholder-secondary/50 focus:outline-none focus:border-brand-400 focus:bg-glassHigh focus:ring-4 focus:ring-[var(--focus-ring)] transition-all"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <Search className="absolute start-3.5 top-3 text-secondary/70 group-focus-within:text-brand-500 transition-colors" size={18} />
          <button className="absolute end-3 top-2.5 text-accent-text bg-accent-subtle p-1 rounded-md hover:bg-brand-300 transition-colors">
            <Filter size={14} />
          </button>
        </div>

        <div className="flex gap-2 overflow-x-auto no-scrollbar pt-1">
          <CategoryChip 
            label={getTranslatedCategory('All')} 
            isActive={activeCategory === 'All'} 
            onClick={() => setActiveCategory('All')} 
          />
          {Object.values(ServiceCategory).map(cat => (
            <CategoryChip 
              key={cat} 
              label={getTranslatedCategory(cat)} 
              isActive={activeCategory === cat} 
              onClick={() => setActiveCategory(cat)} 
            />
          ))}
        </div>
      </div>

      <div className="space-y-8 mt-6">
        {/* Nationality Section */}
        <section className="space-y-4">
           <h2 className="px-5 text-sm font-bold text-primary">{t('section_nationality')}</h2>
           <div className="flex gap-6 overflow-x-auto no-scrollbar px-5 pb-2">
              <div 
                onClick={() => setActiveNationality('All')}
                className="flex flex-col items-center gap-2 cursor-pointer group flex-shrink-0"
              >
                <div className={`w-14 h-14 rounded-full flex items-center justify-center transition-all duration-300 border-2 ${activeNationality === 'All' ? 'border-brand-500 scale-110 shadow-lg shadow-brand-500/20' : 'border-border bg-glassHigh hover:border-brand-300'}`}>
                  <Globe size={24} className={activeNationality === 'All' ? 'text-brand-500' : 'text-secondary'} />
                </div>
                <span className={`text-[10px] font-bold transition-colors ${activeNationality === 'All' ? 'text-brand-500' : 'text-secondary'}`}>{t('cat_all')}</span>
              </div>
              {NATIONALITIES.map(nat => (
                <div 
                  key={nat.name.en}
                  onClick={() => setActiveNationality(nat.name.en)}
                  className="flex flex-col items-center gap-2 cursor-pointer group flex-shrink-0"
                >
                  <div className={`w-14 h-14 rounded-full overflow-hidden transition-all duration-300 border-2 ${activeNationality === nat.name.en ? 'border-brand-500 scale-110 shadow-lg shadow-brand-500/20' : 'border-border hover:border-brand-300'}`}>
                    <img 
                      src={nat.flag} 
                      alt={nat.name[language]} 
                      onError={handleFlagError}
                      className="w-full h-full object-cover" 
                    />
                  </div>
                  <span className={`text-[10px] font-bold transition-colors ${activeNationality === nat.name.en ? 'text-brand-500' : 'text-secondary'}`}>{nat.name[language]}</span>
                </div>
              ))}
           </div>
        </section>

        {continueViewed.length > 0 && (
          <SectionContainer title={t('section_continue')}>
            <div className="flex gap-4 overflow-x-auto no-scrollbar px-5">
              {continueViewed.map(worker => (
                <CompactCard 
                  key={worker.id} 
                  worker={worker} 
                  onClick={() => handleWorkerClick(worker.id)} 
                  language={language}
                />
              ))}
            </div>
          </SectionContainer>
        )}

        {availableNow.length > 0 && (
          <SectionContainer title={t('section_available')}>
            <div className="flex gap-4 overflow-x-auto no-scrollbar px-5">
              {availableNow.map(worker => (
                <CompactCard 
                  key={worker.id} 
                  worker={worker} 
                  onClick={() => handleWorkerClick(worker.id)} 
                  language={language}
                  showAvailability
                />
              ))}
            </div>
          </SectionContainer>
        )}

        <SectionContainer title={t('section_newest')}>
          <div className="px-5 space-y-4">
            {newestListings.slice(0, 4).map(worker => (
              <FullListingCard 
                key={worker.id} 
                worker={worker} 
                onSelect={() => handleWorkerClick(worker.id)}
                onSelectOffice={onSelectOffice}
                language={language}
                t={t}
                dir={dir}
              />
            ))}
          </div>
        </SectionContainer>

        <SectionContainer title={t('section_budget')}>
          <div className="px-5 space-y-4">
            {budgetListings.slice(0, 4).map(worker => (
              <FullListingCard 
                key={worker.id} 
                worker={worker} 
                onSelect={() => handleWorkerClick(worker.id)}
                onSelectOffice={onSelectOffice}
                language={language}
                t={t}
                dir={dir}
              />
            ))}
          </div>
        </SectionContainer>

        <SectionContainer title={t('section_experience')}>
          <div className="px-5 space-y-4">
            {experiencedListings.slice(0, 4).map(worker => (
              <FullListingCard 
                key={worker.id} 
                worker={worker} 
                onSelect={() => handleWorkerClick(worker.id)}
                onSelectOffice={onSelectOffice}
                language={language}
                t={t}
                dir={dir}
              />
            ))}
          </div>
        </SectionContainer>
      </div>
    </div>
  );
};

